mapper.select:
SELECT id, supplier_name, quantity, kwh_equivalent, certificate_year, unit_price, total_amount, status, expected_date, completed_date, purchase_month, expiry_date, is_void, notes, supply_type, location_id, created_by, updated_by, created_at, updated_at, is_deleted FROM procurements WHERE is_deleted = 0
AND status = #{status}
AND is_void =#{isVoid}
ORDER BY created_at DESC
